+fn escape_quoted_file_ref(path: &str, quote: char) -> String {
+    let mut escaped = String::with_capacity(path.len());
+    for ch in path.chars() {
+        if ch == '\\' || ch == quote {
+            escaped.push('\\');
+        }
+        escaped.push(ch);
+    }
+    escaped
